import{_ as e,o,c as i,a2 as t}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"📊 每日市場情緒掃描 — 2026-05-05（週二）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/市場情緒/市場情緒_2026-05-05.md","filePath":"Deep32Q知識庫/市場情緒/市場情緒_2026-05-05.md"}'),r={name:"Deep32Q知識庫/市場情緒/市場情緒_2026-05-05.md"};function l(n,a,s,c,h,d){return o(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="📊-每日市場情緒掃描-—-2026-05-05-週二" tabindex="-1">📊 每日市場情緒掃描 — 2026-05-05（週二） <a class="header-anchor" href="#📊-每日市場情緒掃描-—-2026-05-05-週二" aria-label="Permalink to &quot;📊 每日市場情緒掃描 — 2026-05-05（週二）&quot;">​</a></h1><blockquote><p>查詢時間（TST）：2026-05-05 09:48 Asia/Taipei</p></blockquote><hr><h2 id="一、10-點重點摘要" tabindex="-1">一、10 點重點摘要 <a class="header-anchor" href="#一、10-點重點摘要" aria-label="Permalink to &quot;一、10 點重點摘要&quot;">​</a></h2><h3 id="_1-🌍-荷莫茲海峽危機持續升溫" tabindex="-1">1. 🌍 荷莫茲海峽危機持續升溫 <a class="header-anchor" href="#_1-🌍-荷莫茲海峽危機持續升溫" aria-label="Permalink to &quot;1. 🌍 荷莫茲海峽危機持續升溫&quot;">​</a></h3><p>伊朗自 2026 年 2 月底封锁荷莫茲海峽，僅約 5% 戰前船運量通過。5 月 4 日美國報告擊沉伊朗小型船隻，伊朗否認。美國 5 月 3 日啟動「自由護航行動」（Operation Project Freedom），但局勢仍極度不穩定。布蘭特原油飆至 $114-$119/桶，WTI 達 $105-$106/桶。</p><blockquote><p>來源：Wikipedia 2026 Strait of Hormuz crisis、Bloomberg、Guardian（2026-05-04/05）</p></blockquote><h3 id="_2-💵-美元指數小幅走強" tabindex="-1">2. 💵 美元指數小幅走強 <a class="header-anchor" href="#_2-💵-美元指數小幅走強" aria-label="Permalink to &quot;2. 💵 美元指數小幅走強&quot;">​</a></h3><p>DXY 報 98.47-98.51，較前日上漲 0.11-0.2%。中東衝突維持避險需求，支撐美元。</p><blockquote><p>來源：TradingEconomics、TradingView（2026-05-05）</p></blockquote><h3 id="_3-🇺🇸-美股期貨持平偏弱" tabindex="-1">3. 🇺🇸 美股期貨持平偏弱 <a class="header-anchor" href="#_3-🇺🇸-美股期貨持平偏弱" aria-label="Permalink to &quot;3. 🇺🇸 美股期貨持平偏弱&quot;">​</a></h3><p>S&amp;P 500 期貨 -0.27~0.31%、Nasdaq 期貨 +0.08%、Dow 期貨 +0.18%。前一交易日 S&amp;P 500 與 Nasdaq 達歷史新高後回落，Dow 收跌 557 點（-1.13%）至 48,942 點。</p><blockquote><p>來源：Benzinga、TradingEconomics（2026-05-05）</p></blockquote><h3 id="_4-🇹🇼-台指期大漲站上-41-000-點" tabindex="-1">4. 🇹🇼 台指期大漲站上 41,000 點 <a class="header-anchor" href="#_4-🇹🇼-台指期大漲站上-41-000-點" aria-label="Permalink to &quot;4. 🇹🇼 台指期大漲站上 41,000 點&quot;">​</a></h3><p>5 月 4 日台指期（WTX&amp;）大漲 1,689 點（+4.29%）至 41,031 點，成交量 62,918 口。市場法人預期短期高檔震盪，現貨不追高。</p><blockquote><p>來源：WantGoo、TradingView、Barchart（2026-05-04/05）</p></blockquote><h3 id="_5-₿-比特幣突破-80-000-大關" tabindex="-1">5. ₿ 比特幣突破 $80,000 大關 <a class="header-anchor" href="#_5-₿-比特幣突破-80-000-大關" aria-label="Permalink to &quot;5. ₿ 比特幣突破 $80,000 大關&quot;">​</a></h3><p>BTC 於 5 月 4 日站上 $80,000，為 1 月 31 日以來首見。美國 4 月現貨 ETF 淨流入 $19.7 億為全年最高。Consensus 2026 大會在邁阿密舉行，Coinbase 宣布穩定幣獎勵條款獲參議院共識。但 CryptoQuant 警告漲勢主要由 ETF 流入和槓桿多頭驅動，非現貨買盤。</p><blockquote><p>來源：Crypto.News、HeyGoTrade（2026-05-04/05）</p></blockquote><h3 id="_6-🛢️-原油飆漲觸及四年新高" tabindex="-1">6. 🛢️ 原油飆漲觸及四年新高 <a class="header-anchor" href="#_6-🛢️-原油飆漲觸及四年新高" aria-label="Permalink to &quot;6. 🛢️ 原油飆漲觸及四年新高&quot;">​</a></h3><p>布蘭特原油 $114-$119/桶（四年高），WTI $105-$106/桶。UAE 報告伊朗無人機攻擊石油設施，進一步推升油價。世界銀行預估若衝突升級，布蘭特可能達 $115/桶。</p><blockquote><p>來源：Motley Fool Australia、Investing Live、IBTimes（2026-05-05）</p></blockquote><h3 id="_7-📉-聯準會-4-月維持利率不變" tabindex="-1">7. 📉 聯準會 4 月維持利率不變 <a class="header-anchor" href="#_7-📉-聯準會-4-月維持利率不變" aria-label="Permalink to &quot;7. 📉 聯準會 4 月維持利率不變&quot;">​</a></h3><p>Fed 在 4/28-29 會議以 8-4 票數維持聯邦基金利率 3.50-3.75% 不變，為連續第三次按兵不動。聲明指「下一步更可能降息而非升息」，但多數委員反對暗示降息傾向。下一次 FOMC 為 6/16-17。</p><blockquote><p>來源：Federal Reserve、TheStreet（2026-04-29/05-01）</p></blockquote><h3 id="_8-🌾-農產品市場波動加劇" tabindex="-1">8. 🌾 農產品市場波動加劇 <a class="header-anchor" href="#_8-🌾-農產品市場波動加劇" aria-label="Permalink to &quot;8. 🌾 農產品市場波動加劇&quot;">​</a></h3><p>黃豆期貨（ZSK26）5 月 4 日收 1208&#39;0 美分/蒲式耳（+1.66%），為多週新高。美國播種進度 33%（五年均 23%），阿根廷收割 18.3%（落後五年均）。荷莫茲海峽危機影響糧食運輸，推升運費。</p><blockquote><p>來源：CME Group、USDA、TradingEconomics（2026-05-04）</p></blockquote><h3 id="_9-🚢-波羅的海乾散貨指數持穩" tabindex="-1">9. 🚢 波羅的海乾散貨指數持穩 <a class="header-anchor" href="#_9-🚢-波羅的海乾散貨指數持穩" aria-label="Permalink to &quot;9. 🚢 波羅的海乾散貨指數持穩&quot;">​</a></h3><p>BDI 報 2,730 點（5/1），月增 32.14%，年增 92.12%。受荷莫茲海峽中斷影響，全球海運成本居高不下。</p><blockquote><p>來源：TradingEconomics（2026-05-01）</p></blockquote><h3 id="_10-🔥-本週重要財報與事件" tabindex="-1">10. 🔥 本週重要財報與事件 <a class="header-anchor" href="#_10-🔥-本週重要財報與事件" aria-label="Permalink to &quot;10. 🔥 本週重要財報與事件&quot;">​</a></h3><ul><li><strong>週二</strong>：AMD、HSBC、Shopify 財報</li><li><strong>5/6</strong>：英特磊 Q1 財報董事會 + 法說會</li><li><strong>5/8</strong>：光聖 Q1 財報董事會</li><li><strong>5/20</strong>：NVIDIA Q1 FY2027 財報電話會議</li><li><strong>5/26</strong>：華星光股東會</li></ul><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>TradingEconomics（2026-05-05）：DXY 98.47、S&amp;P/Nasdaq/Dow 期貨、BDI 2,730</li><li>Benzinga（2026-05-05）：S&amp;P 500 futures -0.27%</li><li>WantGoo/Barchart（2026-05-04）：台指期 41,031（+4.29%）</li><li>Crypto.News/HeyGoTrade（2026-05-04/05）：BTC &gt;$80,000</li><li>Motley Fool Australia/IBTimes（2026-05-05）：布蘭特 $114-$119、WTI $105</li><li>Federal Reserve（2026-04-29）：Fed 維持 3.50-3.75%</li><li>CME Group/USDA（2026-05-04）：黃豆 1208&#39;0 美分</li><li>Wikipedia（2026-05-05）：荷莫茲海峽危機</li><li>Investing Live（2026-05-04）：WTI $106.42</li><li>TradingView（2026-05-05）：DXY 98.51</li></ol>',36)])])}const q=e(r,[["render",l]]);export{u as __pageData,q as default};
